{"content": "import { createUser, deleteUser } from './database';
import { app } from './server';
import request from 'supertest';

let testUserId: string;

describe('API', () => {
  beforeAll(async () => {
    testUserId = (await createUser('testuser', 'test@test.com')).id;
  });

  it('should list users', async () => {
    const res = await request(app).get('/api/users');
    expect(res.status).toBe(200);
    expect(res.body.length).toBeGreaterThan(0);
  });

  it('should get user by id', async () => {
    const res = await request(app).get(`/api/users/${testUserId}`);
    expect(res.status).toBe(200);
    expect(res.body.username).toBe('testuser');
  });

  it('should return 404 for missing user', async () => {
    const res = await request(app).get('/api/users/nonexistent-id');
    expect(res.status).toBe(404);
  });
});
"}

Found the problem: `beforeAll` creates a test user but there's no `afterAll` to clean it up. When tests run in a different order, or when the database already has stale test data from a previous run, the `length > 0` check on "list users" might see extra rows, or the test user might already exist and `createUser` fails.

